import{_ as t,o as i,c as o,ag as r}from"./chunks/framework.YaIgwL5o.js";const p=JSON.parse('{"title":"Getting Started","description":"","frontmatter":{},"headers":[],"relativePath":"guide/getting-started.md","filePath":"guide/getting-started.md"}'),a={name:"guide/getting-started.md"};function s(n,e,l,d,h,g){return i(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="getting-started" tabindex="-1">Getting Started <a class="header-anchor" href="#getting-started" aria-label="Permalink to &quot;Getting Started&quot;">​</a></h1><h2 id="what-is-slides-editor" tabindex="-1">What is Slides Editor? <a class="header-anchor" href="#what-is-slides-editor" aria-label="Permalink to &quot;What is Slides Editor?&quot;">​</a></h2><p>Slides Editor is a self-hostable, browser-based WYSIWYG presentation editor built on top of <a href="https://revealjs.com/" target="_blank" rel="noreferrer">reveal.js</a>. It gives you the visual polish of modern slide tools without requiring a cloud account — run it on your laptop, a home server, or a Docker container.</p><p>Unlike editing raw Markdown or HTML reveal.js files, Slides Editor lets you:</p><ul><li><strong>Click and type</strong> directly on slide elements with rich formatting</li><li><strong>Drag, resize, and rotate</strong> text boxes, images, shapes, and code blocks visually</li><li><strong>Preview instantly</strong> — no build step, no reload</li><li><strong>Export anywhere</strong> — HTML, offline HTML, PDF, or PPTX</li></ul><h2 id="key-capabilities" tabindex="-1">Key capabilities <a class="header-anchor" href="#key-capabilities" aria-label="Permalink to &quot;Key capabilities&quot;">​</a></h2><ul><li><strong>Rich text formatting</strong> via TipTap: headings, bold/italic/underline, font size &amp; color, highlight, lists, tables, and code blocks</li><li><strong>LaTeX &amp; TikZ</strong> — write display math or full TikZ diagrams in a split-pane editor with live preview</li><li><strong>Charts</strong> — insert bar, line, and scatter charts from the element menu</li><li><strong>Slide navigation</strong> — vertical stacks, reorderable slides, speaker notes</li><li><strong>Themes &amp; presets</strong> — 11 built-in reveal.js themes plus 6 design presets (Academic, Minimal, Dark Tech, etc.)</li><li><strong>Footer sequences</strong> — automatic section progress footers for academic talks</li><li><strong>Export options</strong> — standalone HTML, offline HTML (CDN inlined), PDF, PPTX, shareable links, GitHub push</li><li><strong>Cloud sync</strong> — Proton Drive, S3, Google Drive, or any rclone remote</li></ul><h2 id="choose-your-installation-method" tabindex="-1">Choose your installation method <a class="header-anchor" href="#choose-your-installation-method" aria-label="Permalink to &quot;Choose your installation method&quot;">​</a></h2><p>Slides Editor can be run in three ways:</p><table tabindex="0"><thead><tr><th>Method</th><th>Best for</th></tr></thead><tbody><tr><td><strong>Docker</strong> (recommended)</td><td>Servers, always-on setups, teams</td></tr><tr><td><strong>Desktop App</strong></td><td>Single-user, offline, local files</td></tr><tr><td><strong>Node.js from source</strong></td><td>Development, customization</td></tr></tbody></table><p>See the <a href="/revealjs_gui/guide/installation.html">Installation guide</a> for step-by-step instructions.</p><h2 id="opening-the-editor" tabindex="-1">Opening the editor <a class="header-anchor" href="#opening-the-editor" aria-label="Permalink to &quot;Opening the editor&quot;">​</a></h2><p>Once running, navigate to <code>http://localhost:3002</code> in your browser. You&#39;ll land on the <strong>home screen</strong>, which shows:</p><ul><li><strong>New Presentation</strong> — create a blank deck or pick a template</li><li><strong>Recent files</strong> — re-open presentations you&#39;ve worked on before</li><li><strong>Open file</strong> — load an existing <code>.json</code> presentation file from disk</li></ul><h2 id="your-first-slide" tabindex="-1">Your first slide <a class="header-anchor" href="#your-first-slide" aria-label="Permalink to &quot;Your first slide&quot;">​</a></h2><ol><li>Click <strong>New Presentation</strong> on the home screen.</li><li>Choose a template (or start blank).</li><li>Click the title text on the first slide and start typing.</li><li>Use the formatting toolbar that appears at the top to change font, size, or color.</li><li>Press <strong>Escape</strong> to deselect and return to slide-selection mode.</li><li>Click the <strong>+</strong> button in the slide panel to add a new slide.</li></ol><h2 id="next-steps" tabindex="-1">Next steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next steps&quot;">​</a></h2><ul><li><a href="/revealjs_gui/guide/installation.html">Installation</a> — detailed setup for Docker, desktop, and source</li><li><a href="/revealjs_gui/tutorials/first-presentation.html">Your First Presentation</a> — a full walkthrough from blank deck to exported file</li></ul>',18)])])}const u=t(a,[["render",s]]);export{p as __pageData,u as default};
